function generateSafeFilename(string $originalName, array $allowedExts): string {
    $extension = strtolower(pathinfo($originalName, PATHINFO_EXTENSION));
    if (!in_array($extension, $allowedExts, true)) {
        throw new RuntimeException('Disallowed file type');
    }
    return bin2hex(random_bytes(18)) . '.' . $extension;
}

function normalizeMetadata(array $input): array {
    // Whitelist of allowed metadata keys
    $allowedKeys = ['description', 'category', 'tags'];
    $normalized = [];

    foreach ($allowedKeys as $key) {
        if (!isset($input[$key])) {
            continue;
        }
        $value = trim((string) $input[$key]);
        // Basic length limits to prevent abuse
        if (strlen($value) > 255) {
            $value = substr($value, 0, 255);
        }
        $normalized[$key] = $value;
    }

    return $normalized;
}

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    try {
