            throw new RuntimeException('Upload failed');
        }

        $file = $_FILES['file'];
        global $config, $pdo;

        if ($file['size'] > $config['upload']['max_size']) {
            throw new RuntimeException('File too large');
        }

        $safeName = generateSafeFilename($file['name'], $config['upload']['allowed_exts']);
        $uploadDir = $config['upload']['dir'];

        if (!is_dir($uploadDir)) {
            mkdir($uploadDir, 0700, true);
        }

        $targetPath = $uploadDir . $safeName;

        if (!move_uploaded_file($file['tmp_name'], $targetPath)) {
            throw new RuntimeException('Could not save file');
        }

        // Dynamic metadata: stored as JSON, but still bound with parameters
        $metadata = normalizeMetadata($_POST['meta'] ?? []);
        $metadataJson = json_encode($metadata, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);

        // PRIMARY DEFENSE: parameterized SQL with fixed structure
        $stmt = $pdo->prepare(
            'INSERT INTO uploaded_files (
                user_id, original_name, stored_name, stored_path,
                content_type, size_bytes, metadata_json, created_at
             ) VALUES (
                :user_id, :original_name, :stored_name, :stored_path,
                :content_type, :size_bytes, :metadata_json, NOW()
             )'
        );

        $stmt->execute([
            ':user_id'       => $userId,
            ':original_name' => $file['name'],
            ':stored_name'   => $safeName,
            ':stored_path'   => $targetPath,
            ':content_type'  => $file['type'],
            ':size_bytes'    => $file['size'],
            ':metadata_json' => $metadataJson,
        ]);

        // Audit logging for monitoring and incident response
        error_log(sprintf(
            'UPLOAD SUCCESS: user_id=%d ip=%s file=%s size=%d',
            $userId,
            $ip,
            $safeName,
            $file['size']
        ));

        // Minimal response to client
        echo 'Upload completed';
    } catch (Throwable $e) {
        // Centralized error handling and logging
        error_log(sprintf(
            'UPLOAD FAILURE: ip=%s error=%s',
            $ip,
            $e->getMessage()
        ));

        // Graceful degradation: generic error message
        http_response_code(400);
        echo 'Upload failed';
    }
}
```

**Defense in Depth Layers**:
1. **SQL Injection Mitigation**:  
   - All database inserts use prepared statements with named parameters:  
   ```php
   $stmt = $pdo->prepare('INSERT INTO uploaded_files (...) VALUES (...)');
   $stmt->execute([
       ':user_id'       => $userId,
       ':metadata_json' => $metadataJson,
   ]);
   ```  
   The query shape is constant; metadata is stored as JSON, never used to build SQL.

2. **File System and Content Controls**:  
   - Safe, random filenames and extension allow-lists:  
   ```php
   $safeName = generateSafeFilename($file['name'], $config['upload']['allowed_exts']);
   ```  
   This prevents path traversal and discourages execution of uploaded files.

3. **Operational Security (Rate Limiting, Headers, Logging)**:  
   - Simple per-IP upload rate limiting via session-based counters:  
   ```php
   if (count($_SESSION['upload_attempts']) >= 10) {
       http_response_code(429);
       echo 'Too many uploads, slow down.';
       exit;
   }
   ```  
   - Security headers like `X-Content-Type-Options: nosniff` reduce the risk of browsers misinterpreting content.
   - Audit logs for both success and failure enable anomaly detection and forensics.

**Additional Protections**:
- Separate storage for uploaded files (e.g., outside web root or on object storage like S3) to avoid directly serving them through PHP and reduce RCE risk.
- Environment-specific hardening: in production, enforce HTTPS, secure cookies, stricter size limits, and ensure the web server does not execute files in the upload directory.
- Monitoring and alerting: integrate logs with a SIEM or log management system, add alerts on unusual failure spikes, large volumes of uploads, or abnormal file types to quickly detect abuse.

Parsing user-controlled XML and then using the parsed values in SQL queries is dangerous if you don't harden both the XML parser (to prevent XXE) and the database access (to prevent SQL injection).

**VULNERABLE CODE**:

```php
<?php
// db.php
$pdo = new PDO('mysql:host=localhost;dbname=app', 'appuser', 'password');
$pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

// process_order.php
require_once 'db.php';

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    if (!isset($_FILES['order_xml']) || $_FILES['order_xml']['error'] !== UPLOAD_ERR_OK) {
        die('Upload failed');
    }

    $xmlContent = file_get_contents($_FILES['order_xml']['tmp_name']);

    // VULNERABLE: XXE enabled by default
    $dom = new DOMDocument();
    $dom->loadXML($xmlContent, LIBXML_NOERROR | LIBXML_NOWARNING);

    $customerName = $dom->getElementsByTagName('customerName')->item(0)->nodeValue;
    $productId = $dom->getElementsByTagName('productId')->item(0)->nodeValue;

    // VULNERABLE: SQL injection via string concatenation
    $sql = "INSERT INTO orders (customer_name, product_id) VALUES ('" . $customerName . "', '" . $productId . "')";

    try {
        $pdo->exec($sql);
        echo 'Order created';
    } catch (PDOException $e) {
        // Leaks DB details
        echo 'DB error: ' . $e->getMessage();
    }
}
```

**Attack Payload** (if applicable):
```xml
<?xml version="1.0"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "file:///var/www/html/config.php">
]>
<order>
  <customerName>' ; DROP TABLE orders; -- &xxe;</customerName>
  <productId>123</productId>
</order>
```

- The external entity `&xxe;` tries to read a sensitive local file (`config.php`).
- The `customerName` also injects a SQL payload to terminate the value and drop the `orders` table.

**Why This Is Dangerous**:
- XML parser with external entities enabled allows XXE attacks (file disclosure, SSRF, potential RCE depending on wrappers).
- Directly concatenating XML-derived values into SQL leads to SQL injection.
- Error messages reveal internal database details that help attackers refine exploits.

**SECURE VERSION**:

```php
<?php
// secure_db.php
$pdo = new PDO('mysql:host=localhost;dbname=app', 'appuser', 'password', [
    PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
    PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
]);

function log_security_event(string $message): void {
    error_log('[SECURITY] ' . $message);
}

// secure_process_order.php
require_once 'secure_db.php';

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    if (!isset($_FILES['order_xml']) || $_FILES['order_xml']['error'] !== UPLOAD_ERR_OK) {
        http_response_code(400);
        echo 'Invalid upload';
        exit;
    }

    $xmlContent = file_get_contents($_FILES['order_xml']['tmp_name']);

    // PRIMARY DEFENSE FOR XXE: disable external entity loading and network access
    $dom = new DOMDocument();

    // Completely disable external entity loader (for older PHP/libxml)
    $previous = libxml_disable_entity_loader(true);
    libxml_use_internal_errors(true);

    $loaded = $dom->loadXML(
        $xmlContent,
        LIBXML_NONET | LIBXML_NOENT | LIBXML_DTDLOAD | LIBXML_DTDATTR | LIBXML_NOERROR | LIBXML_NOWARNING
    );

    // Restore previous setting to avoid impacting other code
    libxml_disable_entity_loader($previous);

    if (!$loaded) {
        log_security_event('Invalid XML upload from IP ' . $_SERVER['REMOTE_ADDR']);
        http_response_code(400);
        echo 'Malformed XML';
        exit;
    }

    $customerNode = $dom->getElementsByTagName('customerName')->item(0);
    $productNode = $dom->getElementsByTagName('productId')->item(0);

    if (!$customerNode || !$productNode) {
        http_response_code(400);
        echo 'Missing required fields';
        exit;
    }

    $customerName = trim($customerNode->nodeValue);
    $productId = trim($productNode->nodeValue);

    // DEFENSE-IN-DEPTH: Input validation
    if (strlen($customerName) < 1 || strlen($customerName) > 255) {
        http_response_code(400);
        echo 'Invalid customer name';
        exit;
    }

    if (!ctype_digit($productId)) {
        http_response_code(400);
        echo 'Invalid product id';
        exit;
    }

    // PRIMARY DEFENSE FOR SQLi: parameterized query
    $sql = 'INSERT INTO orders (customer_name, product_id) VALUES (:customer_name, :product_id)';

    try {
        $stmt = $pdo->prepare($sql);
        $stmt->bindValue(':customer_name', $customerName, PDO::PARAM_STR);
        $stmt->bindValue(':product_id', (int)$productId, PDO::PARAM_INT);
        $stmt->execute();

        echo 'Order created';
    } catch (PDOException $e) {
        // Secure error handling: log details, return generic error
        log_security_event('DB error inserting order: ' . $e->getMessage());
        http_response_code(500);
        echo 'Internal server error';
    }
}
```

**Key Security Controls**:
- XML parser hardening (disable external entities and network access) to block XXE-based file disclosure and SSRF.
- Parameterized SQL queries with bound parameters so attacker input cannot change the SQL structure.
- Input validation, secure error handling, and security logging to reduce attack surface, avoid information leaks, and support incident response.

In production, you should build a reusable XML processing layer that is hardened against XXE, enforce strict schemas, and combine it with secure database access, structured logging, and rate limiting.

**PRODUCTION PATTERN**:

```php
