function app_logger(string $level, string $message, array $context = []): void {
    $entry = [
        'time' => date('c'),
        'level' => $level,
        'message' => $message,
        'context' => $context,
    ];
    error_log(json_encode($entry));
}

function rate_limit(string $key, int $limitPerMinute): bool {
    // Simple in-memory rate limit placeholder; replace with Redis in real prod
    static $counters = [];
    $bucket = date('YmdHi'); // minute precision
    $counterKey = $bucket . ':' . $key;
    if (!isset($counters[$counterKey])) {
        $counters[$counterKey] = 0;
    }
    $counters[$counterKey]++;
    return $counters[$counterKey] <= $limitPerMinute;
}

function parse_order_xml(string $xmlContent): array {
    $dom = new DOMDocument();

    // Defense-in-depth: disable external entities and network access
    $prevDisable = libxml_disable_entity_loader(true);
    libxml_use_internal_errors(true);

    $loaded = $dom->loadXML(
        $xmlContent,
        LIBXML_NONET | LIBXML_NOERROR | LIBXML_NOWARNING
    );

    libxml_disable_entity_loader($prevDisable);

    if (!$loaded) {
        throw new InvalidArgumentException('Malformed XML');
    }

    // Example with namespaces and optional fields
    $xpath = new DOMXPath($dom);
    // If your XML uses namespaces, register them here, e.g.:
    // $xpath->registerNamespace('ns', 'http://example.com/schema');

    $customerNode = $xpath->query('//customerName')->item(0);
    $productNode = $xpath->query('//productId')->item(0);
    $commentNode = $xpath->query('//comment')->item(0); // optional

    if (!$customerNode || !$productNode) {
        throw new InvalidArgumentException('Missing required fields');
    }

    $customerName = trim($customerNode->nodeValue);
    $productId = trim($productNode->nodeValue);
    $comment = $commentNode ? trim($commentNode->nodeValue) : null;

    // Validation layer
    if ($customerName === '' || strlen($customerName) > 255) {
        throw new InvalidArgumentException('Invalid customer name');
    }

    if (!ctype_digit($productId)) {
        throw new InvalidArgumentException('Invalid product id');
    }

    if ($comment !== null && strlen($comment) > 1000) {
        throw new InvalidArgumentException('Comment too long');
    }

    return [
        'customer_name' => $customerName,
        'product_id' => (int)$productId,
        'comment' => $comment,
    ];
}

// api_order.php
require_once __DIR__ . '/bootstrap.php';

header('Content-Type: application/json');
header('X-Content-Type-Options: nosniff');
header('X-Frame-Options: DENY');
