        $pass = 'secret';

        $pdo = new PDO($dsn, $user, $pass, [
            PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
            PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
            PDO::ATTR_EMULATE_PREPARES => false, // use native prepares when possible
        ]);

        if ($env === 'production') {
            // In production you might tune timeouts, SSL, etc.
            // Example: $pdo->setAttribute(PDO::MYSQL_ATTR_USE_BUFFERED_QUERY, true);
        }

        return $pdo;
    }
}

// UserRepository.php
class UserRepository
{
    private PDO $pdo;

    public function __construct(PDO $pdo)
    {
        $this->pdo = $pdo;
    }

    /**
     * Fetch users with optional filters using safe dynamic SQL.
     */
    public function searchUsers(?string $username, ?string $email, int $limit = 20): array
    {
        $where = [];
        $params = [];

        if ($username !== null && $username !== '') {
            // Basic whitelist-style validation
            if (!preg_match('/^[A-Za-z0-9_]{3,32}$/', $username)) {
                throw new InvalidArgumentException('Invalid username format');
            }
            $where[] = 'username LIKE :username';
            $params[':username'] = $username . '%';
        }

        if ($email !== null && $email !== '') {
            if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
                throw new InvalidArgumentException('Invalid email format');
            }
            $where[] = 'email = :email';
            $params[':email'] = $email;
        }

        // Enforce reasonable limits
        if ($limit < 1 || $limit > 100) {
            $limit = 20;
        }

        $sql = 'SELECT id, username, email FROM users';
        if (count($where) > 0) {
            $sql .= ' WHERE ' . implode(' AND ', $where);
        }
        $sql .= ' ORDER BY id DESC LIMIT :limit';

        $stmt = $this->pdo->prepare($sql);

        // Bind dynamic named parameters safely
        foreach ($params as $name => $value) {
            $stmt->bindValue($name, $value, PDO::PARAM_STR);
        }
        $stmt->bindValue(':limit', $limit, PDO::PARAM_INT);

        $stmt->execute();
        return $stmt->fetchAll();
    }
}

// search_users.php
require_once 'config.php';
require_once 'UserRepository.php';

$pdo = Config::getPdo();
$repo = new UserRepository($pdo);

// Simple IP-based rate limiting (very basic example; use a proper middleware in real apps)
session_start();
$ip = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
$now = time();
if (!isset($_SESSION['rate'][$ip])) {
    $_SESSION['rate'][$ip] = ['count' => 0, 'window_start' => $now];
}

$window = &$_SESSION['rate'][$ip];
if ($now - $window['window_start'] > 60) { // 60s window
    $window = ['count' => 0, 'window_start' => $now];
}
$window['count']++;
if ($window['count'] > 60) { // 60 requests/min
    http_response_code(429);
    echo 'Too many requests';
    exit;
}

// Apply minimal security headers
header('X-Content-Type-Options: nosniff');
header('X-Frame-Options: SAMEORIGIN');
header('X-XSS-Protection: 1; mode=block');

$username = isset($_GET['username']) ? trim($_GET['username']) : null;
$email = isset($_GET['email']) ? trim($_GET['email']) : null;

try {
    $users = $repo->searchUsers($username ?: null, $email ?: null);

    // Audit-style logging of search activity (no sensitive data)
    error_log(sprintf(
        'User search from IP %s, filters: username=%s, email_present=%s',
        $ip,
        $username !== null ? '[set]' : '[none]',
        $email !== null ? 'yes' : 'no'
    ));

    header('Content-Type: application/json; charset=utf-8');
    echo json_encode($users, JSON_THROW_ON_ERROR);
} catch (InvalidArgumentException $e) {
    http_response_code(400);
    echo 'Invalid search parameters';
} catch (PDOException $e) {
    // Log DB failures for monitoring/alerting
    error_log('DB error in searchUsers: ' . $e->getMessage());
    http_response_code(500);
    echo 'Internal server error';
} catch (JsonException $e) {
    // Graceful degradation on encoding issues
    error_log('JSON encode error: ' . $e->getMessage());
    http_response_code(500);
    echo 'Internal server error';
}
```

**Defense in Depth Layers**:
1. **Parameterized dynamic SQL construction**:
   - The base query is built with controlled fragments only, and every user-controlled value is passed as a bound parameter:
   ```php
   $where[] = 'username LIKE :username';
   $params[':username'] = $username . '%';
   $stmt = $this->pdo->prepare($sql);
   $stmt->bindValue(':username', $params[':username'], PDO::PARAM_STR);
   ```
   This keeps the SQL structure fixed and prevents injection even with dynamic filters.

2. **Input validation and normalization**:
   - Username and email are validated with regex and `filter_var` before they ever reach the database layer:
   ```php
   if (!preg_match('/^[A-Za-z0-9_]{3,32}$/', $username)) {
       throw new InvalidArgumentException('Invalid username format');
   }
   if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
       throw new InvalidArgumentException('Invalid email format');
   }
   ```
   This reduces unexpected input and helps catch abuse early.

3. **Secure error handling, logging, and basic rate limiting**:
   - All exceptions are caught and logged with `error_log()` while generic responses are sent to clients, and simple request throttling is applied:
   ```php
   error_log('DB error in searchUsers: ' . $e->getMessage());
   http_response_code(500);
   echo 'Internal server error';
   ```
   Combined with the session-based rate limit, this helps detect and slow down probing or brute-force attempts.

**Additional Protections**:
- **Environment-specific configuration**: Centralized `Config::getPdo()` enables different DSNs, credentials, and PDO attributes for development vs. production, including SSL and timeouts.
- **Security headers**: `X-Content-Type-Options`, `X-Frame-Options`, and `X-XSS-Protection` help reduce the impact of any downstream XSS or clickjacking issues in the UI layer.
- **Monitoring and audit logging**: Structured `error_log` entries for search operations and database errors enable integration with log aggregation/alerting systems (e.g., ELK, Splunk) to detect suspicious patterns and potential SQL injection attempts early.

Even with Laravel's query builder, you can introduce SQL injection if you bypass bindings using `whereRaw`, `orderByRaw`, or string-concatenated conditions.

**VULNERABLE CODE**:

```php
<?php

use Illuminate\\Support\\Facades\\DB;
use Illuminate\\Http\\Request;

// routes/web.php

Route::get('/search', function (Request $request) {
    $keyword = $request->query('q', '');
    $sortBy = $request->query('sort', 'created_at');
    $direction = $request->query('dir', 'desc');

    // VULNERABLE: concatenating user input into whereRaw and orderBy
    $products = DB::table('products')
        ->whereRaw("name LIKE '%" . $keyword . "%'")
        ->orderBy(DB::raw($sortBy . ' ' . $direction))
        ->limit(20)
        ->get();

    foreach ($products as $product) {
        echo $product->name . " - " . $product->price . "<br>";
    }
});
```

**Attack Payload** (in URL query string):
```sql
?q=' OR 1=1-- &sort=id); DROP TABLE users; --&dir=
```

- The `q` parameter (`' OR 1=1--`) turns the `WHERE` into a tautology, returning all rows.
- The `sort` parameter injects `); DROP TABLE users; --` into the `ORDER BY` clause, potentially dropping a table if the DB allows stacked queries.

**Why This Is Dangerous**:
- Directly concatenates untrusted input into `whereRaw` and `orderBy`, bypassing Laravel's parameter binding.
- Allows attackers to modify the query structure (WHERE and ORDER BY clauses).
- Can lead to data exfiltration, unauthorized access, or destructive operations like `DROP TABLE`.

**SECURE VERSION**:

```php
<?php

use Illuminate\\Support\\Facades\\DB;
use Illuminate\\Http\\Request;
use Illuminate\\Support\\Facades\\Log;

// routes/web.php

Route::get('/search', function (Request $request) {
    $keyword = $request->query('q', '');
    $sortBy = $request->query('sort', 'created_at');
    $direction = $request->query('dir', 'desc');

    // DEFENSE IN DEPTH: validate and normalize input
    // Allow sorting only by a known whitelist of columns
    $allowedSortColumns = ['created_at', 'price', 'name'];
    if (!in_array($sortBy, $allowedSortColumns, true)) {
        Log::warning('Invalid sort column attempted', [
            'sort' => $sortBy,
            'ip' => $request->ip(),
        ]);
        $sortBy = 'created_at';
    }

    // Normalize direction
    $direction = strtolower($direction) === 'asc' ? 'asc' : 'desc';

    // PRIMARY DEFENSE: use bindings and query builder methods
    try {
        $products = DB::table('products')
            ->when($keyword !== '', function ($query) use ($keyword) {
                // Using where and bindings instead of whereRaw with concatenation
                $query->where('name', 'like', '%' . $keyword . '%');
            })
            ->orderBy($sortBy, $direction)
            ->limit(20)
            ->get();
    } catch (\\Throwable $e) {
        // ERROR HANDLING: log securely, generic message to user
        Log::error('Database error in /search', [
            'exception' => $e->getMessage(),
        ]);

        abort(500, 'Internal server error');
    }

    foreach ($products as $product) {
        echo e($product->name) . " - " . e($product->price) . "<br>";
    }
});
```

**Key Security Controls**:
- **Parameter binding via query builder methods**: Uses `where('name', 'like', ...)` and `orderBy($column, $direction)` with validated values so user input cannot alter SQL structure.
- **Input validation & whitelisting**: Restricts `sort` to a known set of columns and normalizes `dir` to `asc` or `desc`, preventing arbitrary SQL fragments in `ORDER BY`.
- **Secure error handling & logging**: Catches DB exceptions, logs details server-side, and returns a generic error to avoid leaking SQL or schema details to attackers.

In production, you can still support powerful, dynamic search without unsafe raw SQL by combining validated input, parameterized `where`/`orWhere`, and carefully constrained `whereRaw` when absolutely necessary.

**PRODUCTION PATTERN**:

```php
<?php

namespace App\\Http\\Controllers;

use Illuminate\\Http\\Request;
use Illuminate\\Support\\Facades\\DB;
use Illuminate\\Support\\Facades\\Log;
use Illuminate\\Validation\\ValidationException;

class AdminProductSearchController extends Controller
{
    public function index(Request $request)
    {
        // ENV-SPECIFIC CONFIG
        $isProd = app()->environment('production');

        // INPUT VALIDATION (request-level)
        try {
            $validated = $request->validate([
                'q'          => 'nullable|string|max:255',
                'min_price'  => 'nullable|numeric|min:0',
                'max_price'  => 'nullable|numeric|min:0',
                'category'   => 'nullable|string|max:100',
                'in_stock'   => 'nullable|boolean',
                'sort'       => 'nullable|string|in:created_at,price,name',
                'dir'        => 'nullable|string|in:asc,desc',
                'page'       => 'nullable|integer|min:1',
            ]);
        } catch (ValidationException $e) {
            // RATE LIMITING / ABUSE SIGNAL (application-level)
            Log::warning('Invalid search parameters', [
                'errors' => $e->errors(),
                'ip' => $request->ip(),
            ]);
            throw $e; // Laravel will return 422 with validation errors
        }

        $query = DB::table('products');

        // DYNAMIC FILTERS USING SAFE BUILDING BLOCKS
        if (!empty($validated['q'])) {
            $q = $validated['q'];
            $query->where(function ($sub) use ($q) {
                $sub->where('name', 'like', '%' . $q . '%')
                    ->orWhere('description', 'like', '%' . $q . '%');
            });
        }

        if (isset($validated['min_price'])) {
            $query->where('price', '>=', $validated['min_price']);
        }

        if (isset($validated['max_price'])) {
            $query->where('price', '<=', $validated['max_price']);
        }

        if (!empty($validated['category'])) {
            $query->where('category_slug', '=', $validated['category']);
        }

        if (array_key_exists('in_stock', $validated)) {
            $query->where('stock', $validated['in_stock'] ? '>' : '=', 0);
        }

        // VERY LIMITED whereRaw EXAMPLE (computed expression)
        // Only used with parameter binding and no direct user fragments
        if ($request->boolean('discounted_only', false)) {
            $query->whereRaw('(original_price - price) > ?', [5]);
        }

        // SORTING WITH WHITELIST
        $sort = $validated['sort'] ?? 'created_at';
        $dir  = $validated['dir'] ?? 'desc';
        $query->orderBy($sort, $dir);

        // PAGINATION & RESOURCE LIMITS (avoid DoS via huge queries)
        $page     = $validated['page'] ?? 1;
        $perPage  = $isProd ? 50 : 100; // stricter limit in prod

        try {
            $results = $query->paginate($perPage, ['*'], 'page', $page);
        } catch (\Throwable $e) {
            // LOGGING & MONITORING
            Log::error('Admin product search DB error', [
                'exception' => $e->getMessage(),
                'ip' => $request->ip(),
            ]);

            abort(500, 'Internal server error');
        }

        // SECURITY HEADERS / DEFENSE IN DEPTH (if returning a view)
        $response = response()->view('admin.products.search', [
            'results' => $results,
        ]);

        if ($isProd) {
            $response->headers->set('X-Frame-Options', 'SAMEORIGIN');
            $response->headers->set('X-Content-Type-Options', 'nosniff');
            $response->headers->set('Referrer-Policy', 'strict-origin-when-cross-origin');
        }

        // AUDIT LOGGING FOR SENSITIVE ADMIN ACTIONS
        Log::info('Admin product search executed', [
            'admin_id' => optional($request->user())->id,
            'filters'  => $validated,
            'ip'       => $request->ip(),
        ]);

        return $response;
    }
}
```

**Defense in Depth Layers**:
1. **Validated dynamic query construction**:
   - Uses Laravel validation (`$request->validate`) to constrain types and values before they ever reach the query builder.
   - Dynamic `where` and `orWhere` are built from validated, strongly typed values rather than concatenated SQL.

2. **Constrained raw expressions with bindings**:
   - `whereRaw('(original_price - price) > ?', [5])` shows the safe way: the expression is static, and only scalar values are bound.
   - No user-provided strings are concatenated into SQL fragments; all user influence goes through parameters.

3. **Operational security controls (logging, limits, headers)**:
   - Audit logs track admin searches (`admin_id`, filters, IP) for incident response.
   - Pagination and `perPage` limits prevent expensive full-table scans from abusive queries.
   - Security headers reduce other web risks (clickjacking, MIME sniffing) when serving results.

**Additional Protections**:
- **Rate limiting**: In Laravel, use middleware (e.g., `throttle:60,1`) on admin search routes to limit abusive scanning and brute-force behavior.
- **Separation of roles and least privilege**: Ensure the DB user used by the app cannot `DROP` or `ALTER` tables, so even if a query is abused, impact is limited.
- **Centralized query helpers**: Wrap common dynamic filtering patterns in dedicated repository/service methods so developers reuse safe patterns instead of writing ad-hoc `whereRaw` logic.

Passing user input into database-related shell commands (`mysql`, `mysqldump`, etc.) is extremely dangerous. It can lead to **both command injection and SQL injection**, allowing attackers to run arbitrary OS commands or database queries.

**VULNERABLE CODE**:

```php
<?php
// db_backup_vulnerable.php

// Example: backup.php?dbname=testdb&where=id=1
$dbname = $_GET['dbname'] ?? '';
$where  = $_GET['where']  ?? '';

// Hard-coded credentials for demo only (also bad practice)
$dbUser = 'backup_user';
$dbPass = 'backup_pass';

// Build a shell command using user input (DANGEROUS)
// User-controlled variables are directly concatenated
$cmd = "mysql -u{$dbUser} -p{$dbPass} {$dbname} -e \"SELECT * FROM users WHERE {$where};\"";

// Execute the command and capture output
$output = [];
$returnVar = 0;
exec($cmd, $output, $returnVar);

if ($returnVar !== 0) {
    echo "Backup failed"; // Leaks no detail, but the bigger problem is injection
} else {
    header('Content-Type: text/plain');
    echo implode("\n", $output);
}
```

**Attack Payload** (for the `where` parameter):
```sql
1; DROP TABLE users; --
```

This payload results in the final shell command containing:
```text
SELECT * FROM users WHERE 1; DROP TABLE users; --;
```
An attacker could also break out of the SQL context and inject OS commands via shell metacharacters, for example:
```text
1; --"; rm -rf / #
```

**Why This Is Dangerous**:
- User input is directly concatenated into **SQL** without parameters, enabling SQL injection.
- The SQL is then placed unescaped into a **shell command**, enabling command injection with `;`, `&&`, backticks, etc.
- The `exec()` call executes in the OS context of the web server, so compromise can lead to full server takeover.

**SECURE VERSION**:

```php
<?php
// db_backup_secure.php

declare(strict_types=1);

require_once __DIR__ . '/config.php'; // contains DB credentials from env vars

// Simple validation helper
function validateDbName(string $dbname): bool {
    // Allow only alphanumeric and underscore (no spaces, no special chars)
    return (bool)preg_match('/^[A-Za-z0-9_]{1,64}$/', $dbname);
}

function validateId(string $id): bool {
    return ctype_digit($id) && (int)$id > 0;
}

// Get and validate parameters
$dbname = $_GET['dbname'] ?? '';
$id     = $_GET['id']     ?? '';

if (!validateDbName($dbname)) {
    http_response_code(400);
    echo 'Invalid database name';
    exit;
}

if (!validateId($id)) {
    http_response_code(400);
    echo 'Invalid ID';
    exit;
}

// PRIMARY DEFENSE: Use PDO with parameterized queries instead of shelling out
try {
    $dsn = sprintf('mysql:host=%s;dbname=%s;charset=utf8mb4', DB_HOST, $dbname);
    $pdo = new PDO($dsn, DB_USER, DB_PASS, [
        PDO::ATTR_ERRMODE            => PDO::ERRMODE_EXCEPTION,
        PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
    ]);

    $sql = 'SELECT * FROM users WHERE id = :id';
    $stmt = $pdo->prepare($sql);
    $stmt->bindValue(':id', (int)$id, PDO::PARAM_INT);
    $stmt->execute();

    $rows = $stmt->fetchAll();

    header('Content-Type: application/json');
    echo json_encode([
        'status' => 'ok',
        'data'   => $rows,
    ], JSON_THROW_ON_ERROR);
} catch (PDOException $e) {
    // ERROR HANDLING & LOGGING: Log details server-side, generic message to client
    error_log('DB error in backup_secure: ' . $e->getMessage());
    http_response_code(500);
    echo 'Internal server error';
} catch (JsonException $e) {
    error_log('JSON encode error: ' . $e->getMessage());
    http_response_code(500);
    echo 'Internal server error';
}
```

**Key Security Controls**:
- **Eliminate shell calls for DB access**: Use PDO with parameterized queries instead of invoking the `mysql` CLI, removing the command-injection surface.
- **Strict input validation & whitelisting**: Database names and IDs are restricted to safe patterns, blocking dangerous characters like `;`, `&`, `|`, backticks, and quotes.
- **Safe error handling and logging**: Exceptions are logged server-side while clients receive only generic messages, preventing leakage of connection strings, SQL, or system paths.

If you absolutely must call the `mysql` client from PHP (for example, to use features not easily exposed via PDO, or to integrate with legacy backup tooling), you need **multiple layers of defense**:

- Avoid the shell parser entirely by using `proc_open` or argument arrays.
- Rigorously validate and constrain any dynamic parts (whitelist fields/operators, limit complexity).
- Separate **SQL construction** from **OS command arguments**, and never let raw user input reach the shell.

**PRODUCTION PATTERN**:

```php
<?php
// db_backup_production.php

declare(strict_types=1);

require_once __DIR__ . '/config.php';

// Environment-specific configuration
$isProduction = (getenv('APP_ENV') === 'production');

// Simple rate limiting (very basic, use Redis or a proper gateway in real systems)
function rateLimit(string $key, int $limitPerMinute): bool {
    $window = time() - 60;
    $file   = sys_get_temp_dir() . '/ratelimit_' . md5($key);

    $entries = [];
    if (file_exists($file)) {
        $entries = array_filter(explode("\n", file_get_contents($file)), function ($ts) use ($window) {
            return (int)$ts >= $window;
        });
    }

    if (count($entries) >= $limitPerMinute) {
        return false;
    }

    $entries[] = (string)time();
    file_put_contents($file, implode("\n", $entries));
    return true;
}

// Log security-relevant events
function auditLog(string $message, array $context = []): void {
    $ip = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
    $entry = [
        'time'    => date('c'),
        'ip'      => $ip,
        'message' => $message,
        'context' => $context,
    ];
    error_log('[AUDIT] ' . json_encode($entry));
}

function validateDbName(string $dbname): bool {
    return (bool)preg_match('/^[A-Za-z0-9_]{1,64}$/', $dbname);
}

// Whitelist of allowed filter fields and operators
const ALLOWED_FIELDS = ['id', 'status', 'created_at'];
const ALLOWED_OPERATORS = ['=', '>', '<', '>=', '<=', '!='];

function buildSafeWhereClause(array $filters, array &$params): string {
    $clauses = [];
    foreach ($filters as $filter) {
        $field    = $filter['field']    ?? '';
        $operator = $filter['operator'] ?? '=';
        $value    = $filter['value']    ?? '';

        if (!in_array($field, ALLOWED_FIELDS, true)) {
            throw new InvalidArgumentException('Invalid field');
        }
        if (!in_array($operator, ALLOWED_OPERATORS, true)) {
            throw new InvalidArgumentException('Invalid operator');
        }

        // Generate a unique placeholder name per filter
        $placeholder = ':p_' . $field . '_' . count($params);
        $clauses[]   = sprintf('%s %s %s', $field, $operator, $placeholder);
        $params[$placeholder] = $value;
    }

    if (empty($clauses)) {
        return '1=1';
    }

    // Join with AND to keep logic simple
    return implode(' AND ', $clauses);
}

// Apply simple rate limiting (e.g., 10 backup-like calls per minute per IP)
$clientKey = ($_SERVER['REMOTE_ADDR'] ?? 'unknown') . ':backup';
if (!rateLimit($clientKey, 10)) {
    http_response_code(429);
    echo 'Too many requests';
    exit;
}

// Parse and validate input (JSON body: {"dbname": "appdb", "filters": [...]})
$rawBody = file_get_contents('php://input');
$data    = json_decode($rawBody, true) ?? [];

$dbname  = $data['dbname']  ?? '';
$filters = $data['filters'] ?? [];

if (!validateDbName($dbname)) {
    auditLog('Invalid database name in request', ['dbname' => $dbname]);
    http_response_code(400);
    echo 'Invalid database name';
    exit;
}

$params = [];
try {
    $whereClause = buildSafeWhereClause($filters, $params);
} catch (InvalidArgumentException $e) {
    auditLog('Invalid filter in request', ['error' => $e->getMessage()]);
    http_response_code(400);
    echo 'Invalid filters';
    exit;
}

// Build the SQL query safely first using PDO (no shell yet)
try {
    $dsn = sprintf('mysql:host=%s;dbname=%s;charset=utf8mb4', DB_HOST, $dbname);
    $pdo = new PDO($dsn, DB_USER, DB_PASS, [
        PDO::ATTR_ERRMODE            => PDO::ERRMODE_EXCEPTION,
        PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
    ]);

    $sql = 'SELECT * FROM users WHERE ' . $whereClause . ' LIMIT 1000';
    $stmt = $pdo->prepare($sql);

    foreach ($params as $placeholder => $value) {
        $stmt->bindValue($placeholder, $value, PDO::PARAM_STR);
    }

    $stmt->execute();
    $rows = $stmt->fetchAll();

    // Example: write to a temporary file that will be used by a separate
    // offline backup process calling mysql (avoiding exposing shell to user input)
    $tmpFile = tempnam(sys_get_temp_dir(), 'backup_');
    file_put_contents($tmpFile, json_encode($rows));

    auditLog('Backup query executed', [
        'dbname'  => $dbname,
        'filters' => $filters,
        'rows'    => count($rows),
        'file'    => basename($tmpFile),
    ]);

    // Graceful degradation: do not fail hard if backup integration is unavailable
    // Return data to caller; separate daemon can pick up $tmpFile for mysql import/export.

    // Security headers
    if ($isProduction) {
        header('Content-Security-Policy: default-src \"none\"');
        header('X-Content-Type-Options: nosniff');
        header('X-Frame-Options: DENY');
    }

    header('Content-Type: application/json');
    echo json_encode([
        'status'   => 'ok',
        'rows'     => count($rows),
        'backupId' => basename($tmpFile),
    ], JSON_THROW_ON_ERROR);
} catch (PDOException $e) {
    auditLog('Database error during backup', ['error' => $e->getMessage()]);
    http_response_code(500);
    echo 'Internal server error';
} catch (JsonException $e) {
    auditLog('JSON error during backup', ['error' => $e->getMessage()]);
    http_response_code(500);
    echo 'Internal server error';
}
```

**Defense in Depth Layers**:
1. **Strict SQL construction with whitelists**  
   - Only specific fields and operators are allowed:
   ```php
   const ALLOWED_FIELDS = ['id', 'status', 'created_at'];
   const ALLOWED_OPERATORS = ['=', '>', '<', '>=', '<=', '!='];
   ```
   - `buildSafeWhereClause()` uses placeholders and parameter binding, preventing SQL injection even with dynamic WHERE clauses.

2. **Separation of concerns and avoidance of direct shell**  
   - The PHP service uses PDO to perform the query and writes results to a temporary file:
   ```php
   $tmpFile = tempnam(sys_get_temp_dir(), 'backup_');
   file_put_contents($tmpFile, json_encode($rows));
   ```
   - A separate, internal-only backup process can later invoke `mysql` using **fixed** command parameters, not user input.

3. **Monitoring, rate limiting, and audit logging**  
   - Simple rate limiting per IP to reduce brute-force or abuse:
   ```php
   if (!rateLimit($clientKey, 10)) {
       http_response_code(429);
       echo 'Too many requests';
       exit;
   }
   ```
   - `auditLog()` records security-sensitive events (invalid filters, DB errors, backup executions) to server logs for monitoring and incident response.

**Additional Protections**:
- **Environment-specific hardening**: In production, security headers like CSP, `X-Frame-Options`, and `X-Content-Type-Options` are set to reduce other web risks.
- **Least privilege database user**: The `DB_USER` used for these backup-like queries should have read-only access to the necessary tables, limiting impact if compromise occurs.
- **Graceful degradation and isolation**: The backup integration is designed so that failure of downstream `mysql`-based tooling does not expose raw shell commands to the web layer, and does not break the primary API path.

When you combine file uploads with database writes, you can accidentally introduce both file-system and SQL injection risks if you trust user-controlled fields like file name, description, or owner ID.

**VULNERABLE CODE**:

```php
<?php
// db.php
$mysqli = new mysqli('localhost', 'root', 'password', 'filedb');
if ($mysqli->connect_error) {
    die('Connect Error: ' . $mysqli->connect_error);
}

// upload.php
require_once 'db.php';

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $userId      = $_POST['user_id'];              // unvalidated
    $description = $_POST['description'];          // unvalidated
    $fileName    = $_FILES['file']['name'];        // unvalidated
    $tmpName     = $_FILES['file']['tmp_name'];

    // No checks on file type or size
    $uploadDir = __DIR__ . '/uploads/';
    $target    = $uploadDir . $fileName;           // path traversal possible

    if (!move_uploaded_file($tmpName, $target)) {
        die('File upload failed');
    }

    // VULNERABLE: string concatenation into SQL
    $sql = "INSERT INTO uploads (user_id, file_name, description) VALUES (" .
           "'" . $userId . "', '" . $fileName . "', '" . $description . "')";

    if (!$mysqli->query($sql)) {
        die('DB Error: ' . $mysqli->error);        // leaks DB details
    }

    echo 'Upload successful';
}
```

**Attack Payload** (user-controlled `description`):
```sql
'); DROP TABLE uploads; --
```

If the attacker submits that as the description:

Final SQL becomes:
```sql
INSERT INTO uploads (user_id, file_name, description)
VALUES ('5', 'test.pdf', ''); DROP TABLE uploads; --')
```
This allows the attacker to execute arbitrary SQL on the database.

**Why This Is Dangerous**:
- User-controlled data (user_id, description, file_name) is concatenated directly into SQL, enabling SQL injection.
- Unvalidated file name is used in a file path, allowing directory traversal or overwriting sensitive files.
- No validation of file type or size; attackers can upload scripts, malware, or huge files.

**SECURE VERSION**:

```php
<?php
// secure_db.php
$dsn      = 'mysql:host=localhost;dbname=filedb;charset=utf8mb4';
$dbUser   = 'fileapp';
$dbPass   = 'STRONG_DB_PASSWORD';
$options  = [
    PDO::ATTR_ERRMODE            => PDO::ERRMODE_EXCEPTION,
    PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
];

try {
    $pdo = new PDO($dsn, $dbUser, $dbPass, $options);
} catch (PDOException $e) {
    error_log('DB connection error: ' . $e->getMessage());
    http_response_code(500);
    exit('Internal error');
}

// secure_upload.php
require_once 'secure_db.php';

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    // 1. Validate and normalize user input
    if (!isset($_POST['user_id']) || !ctype_digit($_POST['user_id'])) {
        http_response_code(400);
        exit('Invalid user ID');
    }
    $userId = (int) $_POST['user_id'];

    $description = isset($_POST['description']) ? trim($_POST['description']) : '';
    if (strlen($description) > 255) {
        http_response_code(400);
        exit('Description too long');
    }

    if (!isset($_FILES['file']) || $_FILES['file']['error'] !== UPLOAD_ERR_OK) {
        http_response_code(400);
        exit('No file uploaded or upload error');
    }

    $file      = $_FILES['file'];
    $fileSize  = $file['size'];
    $tmpName   = $file['tmp_name'];

    // 2. File size limit (e.g., 5 MB)
    $maxSize = 5 * 1024 * 1024;
    if ($fileSize <= 0 || $fileSize > $maxSize) {
        http_response_code(400);
        exit('Invalid file size');
    }

    // 3. Validate MIME type using finfo
    $finfo    = new finfo(FILEINFO_MIME_TYPE);
    $mimeType = $finfo->file($tmpName);
    $allowed  = [
        'application/pdf'          => 'pdf',
        'image/jpeg'               => 'jpg',
        'image/png'                => 'png',
    ];

    if (!array_key_exists($mimeType, $allowed)) {
        http_response_code(400);
        exit('Unsupported file type');
    }

    // 4. Generate safe server-side file name (do not trust original name)
    $extension  = $allowed[$mimeType];
    $randomName = bin2hex(random_bytes(16)) . '.' . $extension;

    $uploadDir = __DIR__ . '/uploads/';
    if (!is_dir($uploadDir)) {
        mkdir($uploadDir, 0700, true);
    }

    $targetPath = $uploadDir . $randomName;

    // 5. Move uploaded file securely
    if (!move_uploaded_file($tmpName, $targetPath)) {
        error_log('Failed to move uploaded file');
        http_response_code(500);
        exit('Internal error');
    }

    // 6. Insert metadata using parameterized query
    $sql = 'INSERT INTO uploads (user_id, file_name, description, mime_type, size_bytes)
            VALUES (:user_id, :file_name, :description, :mime_type, :size_bytes)';

    try {
        $stmt = $pdo->prepare($sql);
        $stmt->execute([
            ':user_id'     => $userId,
            ':file_name'   => $randomName, // server-generated name
            ':description' => $description,
            ':mime_type'   => $mimeType,
            ':size_bytes'  => $fileSize,
        ]);
    } catch (PDOException $e) {
        // Log detailed error only on the server
        error_log('DB insert error: ' . $e->getMessage());
        // Optionally remove file if DB insert fails
        if (file_exists($targetPath)) {
            unlink($targetPath);
        }
        http_response_code(500);
        exit('Internal error');
    }

    // 7. Minimal success response
    echo 'File uploaded successfully';
}
```

**Key Security Controls**:
- **Parameterized SQL queries (PDO prepared statements)**: User input is bound as data, not as part of the SQL structure, preventing SQL injection even if fields contain quotes or SQL-looking content.
- **Strict file validation and safe storage**: Uses MIME type checking, file size limits, and a random server-side file name in a controlled directory to prevent arbitrary code upload, path traversal, and overwriting critical files.
- **Robust error handling and logging**: Returns generic error messages to clients while logging detailed errors server-side, reducing information leakage and enabling incident investigation.

In production, a secure upload/download system must combine safe SQL patterns with strict authorization, careful dynamic query building, and strong operational controls (logging, rate limiting, environment config).

**PRODUCTION PATTERN**:

```php
<?php
// config.php
return [
    'env'        => getenv('APP_ENV') ?: 'production',
    'db_dsn'     => getenv('DB_DSN'),
    'db_user'    => getenv('DB_USER'),
    'db_pass'    => getenv('DB_PASS'),
    'log_file'   => __DIR__ . '/logs/app.log',
    'rate_limit' => 100, // requests per hour per IP
];

// bootstrap.php
$config = require __DIR__ . '/config.php';

ini_set('log_errors', '1');
ini_set('error_log', $config['log_file']);

if ($config['env'] === 'production') {
    ini_set('display_errors', '0');
} else {
    ini_set('display_errors', '1');
}

$pdo = new PDO(
    $config['db_dsn'],
    $config['db_user'],
    $config['db_pass'],
    [
        PDO::ATTR_ERRMODE            => PDO::ERRMODE_EXCEPTION,
        PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
    ]
);

session_start();

function current_user_id(): ?int {
    return isset($_SESSION['user_id']) ? (int) $_SESSION['user_id'] : null;
}

function require_auth(): int {
    $uid = current_user_id();
    if (!$uid) {
        http_response_code(401);
        exit('Unauthorized');
    }
    return $uid;
}

function rate_limit(string $key, int $limitPerHour): void {
    // Very simple in-memory rate limit example (for demo only).
    // In real production, use Redis or a dedicated rate limiter.
    static $hits = [];
    $now  = time();
    $hour = 3600;

    if (!isset($hits[$key])) {
        $hits[$key] = [];
    }

    // Remove entries older than 1 hour
    $hits[$key] = array_filter($hits[$key], function ($ts) use ($now, $hour) {
        return $ts > $now - $hour;
    });

    if (count($hits[$key]) >= $limitPerHour) {
        http_response_code(429);
        exit('Too many requests');
    }

    $hits[$key][] = $now;
}

// download.php
require __DIR__ . '/bootstrap.php';

$method = $_SERVER['REQUEST_METHOD'];
$path   = parse_url($_SERVER['REQUEST_URI'], PHP_URL_PATH);

// Simple routing example
if ($method === 'GET' && $path === '/files') {
    // List or filter user's files
    $userId = require_auth();

    $clientIp   = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
    rate_limit('list:' . $clientIp, $config['rate_limit']);

    $queryParams = [];
    $conditions  = ['user_id = :user_id'];
    $queryParams[':user_id'] = $userId;

    // Optional safe filters
    if (!empty($_GET['from_date']) && !empty($_GET['to_date'])) {
        $from = $_GET['from_date'];
        $to   = $_GET['to_date'];
        // Basic date validation (YYYY-MM-DD)
        if (!preg_match('/^\d{4}-\d{2}-\d{2}$/', $from) ||
            !preg_match('/^\d{4}-\d{2}-\d{2}$/', $to)) {
            http_response_code(400);
            exit('Invalid date format');
        }
        $conditions[]             = 'created_at BETWEEN :from_date AND :to_date';
        $queryParams[':from_date'] = $from . ' 00:00:00';
        $queryParams[':to_date']   = $to . ' 23:59:59';
    }

    // Optional file type filter with whitelist
    if (!empty($_GET['type'])) {
        $type = $_GET['type'];
        $allowedTypes = ['pdf', 'image'];
        if (!in_array($type, $allowedTypes, true)) {
            http_response_code(400);
            exit('Invalid type filter');
        }
        if ($type === 'pdf') {
            $conditions[] = 'mime_type = :mime_pdf';
            $queryParams[':mime_pdf'] = 'application/pdf';
        } elseif ($type === 'image') {
            $conditions[] = 'mime_type IN (:mime_jpg, :mime_png)';
            // Need separate named params
            $queryParams[':mime_jpg'] = 'image/jpeg';
            $queryParams[':mime_png'] = 'image/png';
        }
    }

    $whereSql = implode(' AND ', $conditions);
    $sql      = "SELECT id, file_name, description, mime_type, size_bytes, created_at
                 FROM uploads
                 WHERE $whereSql
                 ORDER BY created_at DESC
                 LIMIT 100"; // hard limit for safety

    try {
        $stmt = $pdo->prepare($sql);
        $stmt->execute($queryParams);
        $files = $stmt->fetchAll();
    } catch (PDOException $e) {
        error_log('File list error: ' . $e->getMessage());
        http_response_code(500);
        exit('Internal error');
    }

    header('Content-Type: application/json');
    echo json_encode($files);
    exit;
}

if ($method === 'GET' && $path === '/files/download') {
    // Download a specific file by ID, ensuring ownership
    $userId = require_auth();

    $clientIp = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
    rate_limit('download:' . $clientIp, $config['rate_limit']);

    if (empty($_GET['id']) || !ctype_digit($_GET['id'])) {
        http_response_code(400);
        exit('Invalid file ID');
    }
    $fileId = (int) $_GET['id'];

    $sql = 'SELECT id, user_id, file_name, mime_type, size_bytes
            FROM uploads
            WHERE id = :id AND user_id = :user_id
            LIMIT 1';

    try {
        $stmt = $pdo->prepare($sql);
        $stmt->execute([
            ':id'      => $fileId,
            ':user_id' => $userId,
        ]);

        $file = $stmt->fetch();
        if (!$file) {
            http_response_code(404);
            exit('File not found');
        }
    } catch (PDOException $e) {
        error_log('File fetch error: ' . $e->getMessage());
        http_response_code(500);
        exit('Internal error');
    }

    $filePath = __DIR__ . '/uploads/' . $file['file_name'];

    if (!is_readable($filePath)) {
        error_log('File missing on disk: ' . $filePath);
        http_response_code(410); // Gone
        exit('File unavailable');
    }

    // Audit log download
    error_log(sprintf(
        'DOWNLOAD: user_id=%d file_id=%d ip=%s time=%s',
        $userId,
        $fileId,
        $clientIp,
        date('c')
    ));

    // Send security headers
    header('Content-Type: ' . $file['mime_type']);
    header('Content-Length: ' . (string) $file['size_bytes']);
    header('Content-Disposition: attachment; filename="file-' . $file['id'] . '"');
    header('X-Content-Type-Options: nosniff');
    header('X-Frame-Options: DENY');
    header('X-XSS-Protection: 1; mode=block');

    // Stream file
    $fp = fopen($filePath, 'rb');
    if ($fp === false) {
        http_response_code(500);
        exit('Internal error');
    }

    while (!feof($fp)) {
        echo fread($fp, 8192);
        flush();
    }
    fclose($fp);
    exit;
}

http_response_code(404);
exit('Not found');
```

**Defense in Depth Layers**:
1. **Safe dynamic SQL construction with strict validation and parameter binding**:
   - Filters like dates and types are validated via regex and whitelists before being added to the `WHERE` clause.
   - All dynamic values are passed through named parameters (`:from_date`, `:mime_pdf`, etc.), preventing SQL injection even when multiple optional filters are combined.

2. **Strong authentication, authorization, and least privilege**:
   - `require_auth()` ensures only authenticated users access listing and download endpoints.
   - Download queries enforce ownership with `WHERE id = :id AND user_id = :user_id`, preventing users from downloading other users’ files even if they guess IDs.

3. **Operational controls: rate limiting, logging, and secure headers**:
   - `rate_limit()` throttles list and download requests per IP to reduce brute-force and scraping.
   - `error_log()` records database errors and download events (user ID, file ID, IP, timestamp) for audit trails and anomaly detection.
   - Security headers (`X-Content-Type-Options`, `X-Frame-Options`, `X-XSS-Protection`) reduce the risk of content-type sniffing, clickjacking, and some browser-based attacks.

**Additional Protections**:
- **Environment-specific configuration**: Sensitive settings (DB credentials, environment) are loaded from environment variables and config files, not hard-coded, allowing stricter settings (no error display, stronger logging) in production.
- **Graceful degradation and minimal error messages**: Users receive generic messages and proper HTTP status codes (400, 401, 404, 410, 429, 500) while details are logged server-side, limiting information disclosure but enabling debugging.
- **Hard limits and safe defaults**: Query results capped with `LIMIT 100`, validated date formats, constrained MIME types, and numeric ID checks all reduce the attack surface for injection and resource abuse.

When you parse untrusted XML and then use values inside SQL queries, you risk **XML External Entity (XXE) attacks plus SQL injection** if you aren't careful.

**VULNERABLE CODE**:

```php
<?php
// db.php
$pdo = new PDO('mysql:host=localhost;dbname=shop', 'shop_user', 'shop_pass');
$pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

// vulnerable.php
require_once 'db.php';

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $xmlString = $_POST['order_xml'] ?? '';

    // 1) Insecure XML parsing with XXE enabled by default
    $dom = new DOMDocument();
    // No options to disable external entities or DTDs
    $dom->loadXML($xmlString, LIBXML_NOERROR | LIBXML_NOWARNING);

    $orderNumber = $dom->getElementsByTagName('orderNumber')->item(0)->nodeValue ?? '';

    // 2) Directly concatenate into SQL query (SQL injection risk)
    $sql = "SELECT * FROM orders WHERE order_number = '" . $orderNumber . "'";

    try {
        $stmt = $pdo->query($sql); // Dangerous: dynamic SQL from untrusted XML
        $order = $stmt->fetch(PDO::FETCH_ASSOC);

        if ($order) {
            echo "Order found: " . htmlspecialchars($order['order_number']);
        } else {
            echo "Order not found";
        }
    } catch (PDOException $e) {
        // Leaks internal error details
        echo "DB error: " . $e->getMessage();
    }
} else {
    // Simple demo form
    ?>
    <form method="POST">
        <textarea name="order_xml" rows="10" cols="60"></textarea>
        <button type="submit">Submit</button>
    </form>
    <?php
}
```

**Attack Payload** (XXE to read local file, plus SQL injection via XML field):
```xml
<?xml version="1.0"?>
<!DOCTYPE data [
  <!ENTITY xxe SYSTEM "file:///etc/passwd">
]>
<order>
  <orderNumber'> OR '1'='1">&xxe;</orderNumber'> OR '1'='1">
</order>
```

- The `xxe` entity attempts to read `/etc/passwd` when XML is parsed.
- The crafted `orderNumber` value closes the quote and injects `OR '1'='1'`, returning all orders.

**Why This Is Dangerous**:
- XXE allows attackers to read arbitrary files, perform SSRF, or cause DoS via entity expansion.
- Concatenating XML-derived data into SQL queries enables classic SQL injection.
- Exposing raw database errors gives attackers information about schema and internals.

**SECURE VERSION**:

```php
<?php
// secure_db.php
$pdo = new PDO('mysql:host=localhost;dbname=shop', 'shop_user', 'shop_pass');
$pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

function getOrderByNumber(PDO $pdo, string $orderNumber): ?array {
    // Primary defense: parameterized query
    $sql = 'SELECT * FROM orders WHERE order_number = :order_number';
    $stmt = $pdo->prepare($sql);
    $stmt->bindParam(':order_number', $orderNumber, PDO::PARAM_STR);
    $stmt->execute();
    $result = $stmt->fetch(PDO::FETCH_ASSOC);
    return $result ?: null;
}

function parseOrderXml(string $xmlString): ?string {
    if ($xmlString === '') {
        return null;
    }

    // Secure XML parsing: disable external entities and DTDs
    $prevDisableEntityLoader = libxml_disable_entity_loader(true);
    $prevUseInternalErrors = libxml_use_internal_errors(true);

    $dom = new DOMDocument();
    $success = $dom->loadXML(
        $xmlString,
        LIBXML_NONET         // Disallow network
        | LIBXML_NOENT       // Avoid expanding entities
        | LIBXML_DTDLOAD     // Will be ignored when entity loader disabled
        | LIBXML_DTDATTR
        | LIBXML_NOERROR
        | LIBXML_NOWARNING
    );

    // Restore previous libxml settings
    libxml_disable_entity_loader($prevDisableEntityLoader);
    libxml_use_internal_errors($prevUseInternalErrors);

    if (!$success) {
        error_log('Invalid XML input received');
        return null;
    }

    $orderNumberNode = $dom->getElementsByTagName('orderNumber')->item(0);
    if (!$orderNumberNode) {
        return null;
    }

    $orderNumber = trim($orderNumberNode->nodeValue);

    // Defense in depth: strict input validation
    if (!preg_match('/^[A-Z0-9\-]{1,20}$/', $orderNumber)) {
        // Only uppercase letters, digits, hyphen, max length 20
        error_log('Rejected suspicious order number: ' . $orderNumber);
        return null;
    }

    return $orderNumber;
}

// secure_handler.php
require_once 'secure_db.php';

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $xmlString = $_POST['order_xml'] ?? '';

    $orderNumber = parseOrderXml($xmlString);
    if ($orderNumber === null) {
        http_response_code(400);
        echo 'Invalid order XML or order number.';
        exit;
    }

    try {
        $order = getOrderByNumber($pdo, $orderNumber);
        if ($order) {
            echo 'Order found: ' . htmlspecialchars($order['order_number'], ENT_QUOTES, 'UTF-8');
        } else {
            echo 'Order not found';
        }
    } catch (PDOException $e) {
        // Fail securely: generic message, detailed log
        error_log('Database error in order lookup: ' . $e->getMessage());
        http_response_code(500);
        echo 'Internal server error.';
    }
} else {
    ?>
    <form method="POST">
        <textarea name="order_xml" rows="10" cols="60"></textarea>
        <button type="submit">Submit</button>
    </form>
    <?php
}
```

**Key Security Controls**:
- **XXE hardening**: `libxml_disable_entity_loader(true)` with `LIBXML_NONET` prevents external entity resolution and network access during XML parsing.
- **Parameterized SQL**: Using prepared statements with named parameters (`:order_number`) prevents SQL injection by separating code from data regardless of XML content.
- **Input validation and safe error handling**: Strict regex validation on `orderNumber`, generic error messages for the client, and detailed logging (`error_log`) for operators reduce attack surface and information leakage.

In production, you should treat the XML parsing and SQL query-building as two separate, hardened components: a safe XML-to-DTO mapper and a dynamic-but-parameterized query builder, with robust logging and environment-aware settings.

**PRODUCTION PATTERN**:

```php
<?php
// config.php
class AppConfig {
    public const ENV = 'production'; // 'development' or 'production'

    public static function getPdo(): PDO {
        $dsn = 'mysql:host=localhost;dbname=shop;charset=utf8mb4';
        $user = 'shop_user';
        $pass = 'shop_pass';

        $pdo = new PDO($dsn, $user, $pass, [
            PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
            PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
        ]);

        return $pdo;
    }
}

// XmlOrderFilter.php
class XmlOrderFilter {
    public ?string $orderNumber = null;
    public ?string $customerEmail = null;
    public ?string $status = null;
    public ?string $fromDate = null;
    public ?string $toDate = null;

    public static function fromXml(string $xml): ?self {
        if ($xml === '') {
            return null;
        }

        $prevDisableEntityLoader = libxml_disable_entity_loader(true);
        $prevUseInternalErrors = libxml_use_internal_errors(true);

        $dom = new DOMDocument();
        $ok = $dom->loadXML(
            $xml,
            LIBXML_NONET | LIBXML_NOERROR | LIBXML_NOWARNING
        );

        libxml_disable_entity_loader($prevDisableEntityLoader);
        libxml_use_internal_errors($prevUseInternalErrors);

        if (!$ok) {
            error_log('Invalid filter XML received');
            return null;
        }

        $filter = new self();

        // Helper closure to get trimmed node text safely
        $getText = static function (DOMDocument $dom, string $tag): ?string {
            $node = $dom->getElementsByTagName($tag)->item(0);
            if (!$node) {
                return null;
            }
            $value = trim($node->nodeValue);
            return $value === '' ? null : $value;
        };

        $filter->orderNumber = $getText($dom, 'orderNumber');
        $filter->customerEmail = $getText($dom, 'customerEmail');
        $filter->status = $getText($dom, 'status');
        $filter->fromDate = $getText($dom, 'fromDate');
        $filter->toDate = $getText($dom, 'toDate');

        // Validation layer
        if ($filter->orderNumber !== null && !preg_match('/^[A-Z0-9\-]{1,20}$/', $filter->orderNumber)) {
            error_log('Rejected orderNumber in XML: ' . $filter->orderNumber);
            $filter->orderNumber = null;
        }

        if ($filter->customerEmail !== null && !filter_var($filter->customerEmail, FILTER_VALIDATE_EMAIL)) {
            error_log('Rejected email in XML: ' . $filter->customerEmail);
            $filter->customerEmail = null;
        }

        if ($filter->status !== null && !in_array($filter->status, ['NEW', 'SHIPPED', 'CANCELLED'], true)) {
            error_log('Rejected status in XML: ' . $filter->status);
            $filter->status = null;
        }

        $datePattern = '/^\d{4}-\d{2}-\d{2}$/';
        if ($filter->fromDate !== null && !preg_match($datePattern, $filter->fromDate)) {
            error_log('Rejected fromDate in XML: ' . $filter->fromDate);
            $filter->fromDate = null;
        }
        if ($filter->toDate !== null && !preg_match($datePattern, $filter->toDate)) {
            error_log('Rejected toDate in XML: ' . $filter->toDate);
            $filter->toDate = null;
        }

        return $filter;
    }
}

// OrderRepository.php
class OrderRepository {
    private PDO $pdo;

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
    }

    /**
     * Builds a dynamic, parameterized query from an XmlOrderFilter.
     */
    public function search(XmlOrderFilter $filter, int $limit = 50): array {
        $sql = 'SELECT order_number, customer_email, status, created_at FROM orders WHERE 1=1';
        $params = [];

        if ($filter->orderNumber !== null) {
            $sql .= ' AND order_number = :order_number';
            $params[':order_number'] = $filter->orderNumber;
        }
        if ($filter->customerEmail !== null) {
            $sql .= ' AND customer_email = :customer_email';
            $params[':customer_email'] = $filter->customerEmail;
        }
        if ($filter->status !== null) {
            $sql .= ' AND status = :status';
            $params[':status'] = $filter->status;
        }
        if ($filter->fromDate !== null) {
            $sql .= ' AND created_at >= :from_date';
            $params[':from_date'] = $filter->fromDate . ' 00:00:00';
        }
        if ($filter->toDate !== null) {
            $sql .= ' AND created_at <= :to_date';
            $params[':to_date'] = $filter->toDate . ' 23:59:59';
        }

        // Defense: enforce sane, bounded limits
        $limit = max(1, min($limit, 100));
        $sql .= ' ORDER BY created_at DESC LIMIT :limit';

        $stmt = $this->pdo->prepare($sql);

        foreach ($params as $name => $value) {
            $stmt->bindValue($name, $value, PDO::PARAM_STR);
        }
        $stmt->bindValue(':limit', $limit, PDO::PARAM_INT);

        $stmt->execute();
        return $stmt->fetchAll();
    }
}

